INSERT INTO `activity_type_daily_logs` (`id`, `activity_type_id`, `day_number`, `day_title`, `task_description`, `task_title`, `script_idea`, `script_title`, `feedback`, `audio_url`, `required_listen_percent`, `require_user_response`, `is_mcq`, `mcq_question`, `mcq_options`, `mcq_correct_option`, `notification_enabled`, `morning_reminder_enabled`, `evening_reminder_enabled`, `morning_reminder_time`, `evening_reminder_time`, `reminder_time`, `created_at`, `updated_at`) VALUES
(2, 20, 1, NULL, 'Break the Rejection Myth \n\nThe belief “clients will reject me” lowers confidence and weakens your pitch.\nShifting to “clients value guidance” builds trust and authority', NULL, 'What do you currently think when approaching a client, and how will you reframe it into a stronger belief? Also, what action will you take today?', NULL, NULL, NULL, 0, 1, 0, NULL, NULL, NULL, 0, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-11 06:41:43', '2026-04-11 06:41:43'),
(3, 16, 1, NULL, 'Own Your Realtor Identity\n\nHow you see yourself shapes how clients see you. If your identity is unclear, your communication feels weak. When you define a strong identity, your presence becomes confident and trusted.', NULL, 'How do you currently see yourself as a realtor, and how will you redefine your identity to show more authority? What action will you take today to reflect this?', NULL, NULL, NULL, 0, 1, 0, NULL, NULL, NULL, 0, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-11 06:45:15', '2026-04-11 06:45:15'),
(4, 14, 1, NULL, 'Reset Before the Call\n\n\nBefore an important call, your state matters more than your script.\nA calm mind leads to clear communication and better control.', NULL, '1. Inhale deeply for 4 seconds\n2. Hold for 2 seconds\n3. Exhale slowly for 6 seconds\n4. Repeat this for 5 breaths', NULL, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, 0, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-11 06:49:58', '2026-04-11 06:49:58'),
(5, 3, 1, NULL, 'Stay Consistent, Win Daily\n\n\nSuccess in real estate doesn’t come from occasional effort.It comes from showing up consistently, even on low-motivation days.', NULL, 'Listen to this short audio before starting your work today.', NULL, NULL, '/api/stream/1775892967_Audio%20Reprogramming.mpeg', 0, 0, 0, NULL, NULL, NULL, 0, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-11 07:36:38', '2026-04-11 07:36:38'),
(6, 18, 1, NULL, 'Morning Focus Ritual: Top 3 Priorities\n\n\nTop realtors don’t start their day reacting, they start with clarity.\nDefining your top 3 priorities ensures your effort turns into results.', NULL, 'Identify your 3 most important actions that directly move deals forward today.\n\nList your top 3 priorities for today and what outcome you expect from them.', NULL, NULL, NULL, 0, 1, 0, NULL, NULL, NULL, 0, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-11 06:55:45', '2026-04-11 06:55:45'),
(7, 19, 1, NULL, 'Discipline Over Motivation\n\n\nMotivation is temporary - it comes and goes.\nDiscipline is what ensures consistent action, even on low-energy days.\n\nTop realtors don’t rely on how they feel.\nThey focus on what must be done — starting with their top 3 priorities every morning.', NULL, 'Where are you currently relying on motivation instead of discipline? What are the top 3 priorities you will commit to today, regardless of how you feel?', NULL, NULL, NULL, 0, 1, 0, NULL, NULL, NULL, 0, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-11 07:00:27', '2026-04-11 07:00:27'),
(8, 15, 1, NULL, 'Gratitude Reset: Your Career\n\n\nIn real estate, it’s easy to focus on pressure and results.\nGratitude shifts your focus to what’s already working — building confidence and clarity.', NULL, 'List three things you appreciate about your career as a realtor today.', NULL, NULL, NULL, 0, 1, 0, NULL, NULL, NULL, 0, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-11 07:02:01', '2026-04-11 07:02:01'),
(14, 2, 1, 'DAY 1', NULL, 'TASK DESCRIPTION', NULL, 'QUESTION / PROMPT (OPTIONAL)', NULL, '/api/stream/1776410437_Affirmation%20For%20Realtor.m4a', 0, 0, 0, NULL, '[]', NULL, 1, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-17 07:20:38', '2026-04-17 07:20:38'),
(15, 2, 2, 'DAY 2', NULL, 'TASK DESCRIPTION', NULL, 'QUESTION / PROMPT (OPTIONAL)', NULL, '/api/stream/1776415156_Dubai%20realtor%20affirmation.mp3.mpeg', 0, 0, 0, NULL, '[]', NULL, 1, 1, 1, '09:00:00', '18:00:00', '18:00:00', '2026-04-17 08:39:16', '2026-04-17 08:39:16');
