(162, 28, NULL, 'assistant', 'Hello Iconic Leader! How can I assist you in smashing your goals today?\n\n[View Today\'s Tasks]', '2026-04-29 06:48:03', '2026-04-29 06:48:03', 621, 23, 644, 'google/gemini-2.5-flash-lite-preview-09-2025'),
(163, 28, 5, 'user', 'did i ask this ?', '2026-04-29 06:48:20', '2026-04-29 06:48:20', NULL, NULL, NULL, NULL),
(164, 28, NULL, 'assistant', 'Sometimes context gets lost! You just greeted me with \"hey.\"\n\nAre you looking for something specific from our earlier conversation, like your courses or clients?\n[Check Courses]', '2026-04-29 06:48:22', '2026-04-29 06:48:22', 649, 36, 685, 'google/gemini-2.5-flash-lite-preview-09-2025'),
(165, 28, 5, 'user', '.what are u doing', '2026-04-29 06:48:37', '2026-04-29 06:48:37', NULL, NULL, NULL, NULL),
(166, 28, NULL, 'assistant', 'I am here and ready to support your success, Iconic Leader! Right now, I\'m waiting for your next request.\n\nWould you like to check your daily tasks or review your momentum score?\n[Go to Dashboard]', '2026-04-29 06:48:39', '2026-04-29 06:48:39', 690, 46, 736, 'google/gemini-2.5-flash-lite-preview-09-2025'),
(167, 28, 5, 'user', 'don’t show me Clint name', '2026-04-29 06:49:02', '2026-04-29 06:49:02', NULL, NULL, NULL, NULL),
(168, 28, NULL, 'assistant', 'Understood, Iconic Leader. I will not mention specific client names unless you ask directly for CRM data.\n\nHow can I help you focus on training or tasks right now?\n[View My Daily Tasks]', '2026-04-29 06:49:04', '2026-04-29 06:49:04', 743, 42, 785, 'google/gemini-2.5-flash-lite-preview-09-2025'),
(169, 28, 5, 'user', 'why u are showing this agin and agin', '2026-04-29 06:49:28', '2026-04-29 06:49:28', NULL, NULL, NULL, NULL),
(170, 28, NULL, 'assistant', 'I apologize if I seem repetitive, Iconic Leader. I aim to keep things concise.\n\nYou are asking how to navigate the app or what I am doing. If you want to see a specific section, just tell me which one.\n\nWhich area are you interested in now?\n[Go to Leaderboard]', '2026-04-29 06:49:30', '2026-04-29 06:49:30', 795, 63, 858, 'google/gemini-2.5-flash-lite-preview-09-2025'),
(171, 29, 5, 'user', 'hy', '2026-04-29 06:49:46', '2026-04-29 06:49:46', NULL, NULL, NULL, NULL),
(172, 29, NULL, 'assistant', 'Hello Iconic Leader! How can I help you get started today?\n\n[View Dashboard]', '2026-04-29 06:49:47', '2026-04-29 06:49:47', 450, 18, 468, 'google/gemini-2.5-flash-lite-preview-09-2025'),
(173, 29, 5, 'user', 'what is my review this month', '2026-04-29 06:50:00', '2026-04-29 06:50:00', NULL, NULL, NULL, NULL),
